tableData:
{{
(() => {

  const data = GetRisksAll.data?.data || GetRisksAll.data || [];

  const probMap = { Low: 1, Medium: 2, High: 3 };
  const impactMap = { Low: 1, Medium: 2, High: 3 };

  const grouped = {};

  data.forEach(r => {

    const po = r.MicrossSalesOrderReference;
    if (!po) return;

    if (!grouped[po]) {
      grouped[po] = {
        MicrossSalesOrderReference: po,
        totalScore: 0,
        maxScore: 0,
        unmitigated: 0
      };
    }

    const isUnmitigated =
      !r.Mitigation || r.Mitigation.toString().trim() === "";

    if (!isUnmitigated) return;   // 🔥 THIS IS THE FIX

    const p = probMap[r.Probability] || 0;
    const i = impactMap[r.Impact] || 0;

    const score = p * i;

    grouped[po].totalScore += score;
    grouped[po].maxScore += 9;
    grouped[po].unmitigated += 1;

  });

  return Object.values(grouped)
    .map(r => {

      const scoreOutOf10 = r.maxScore
        ? ((r.totalScore / r.maxScore) * 10)
        : 0;

      const rounded = Math.round(scoreOutOf10 * 10) / 10;

      let level = "Low";
      if (rounded >= 7) level = "High";
      else if (rounded >= 4) level = "Medium";

      return {
        MicrossSalesOrderReference: r.MicrossSalesOrderReference,
        OverallRiskScore: `${rounded}/10`,
        RiskLevel: level,
        UnmitigatedRisks: r.unmitigated,
        _scoreRaw: rounded
      };

    })
    .sort((a, b) => b._scoreRaw - a._scoreRaw);

})()
}}
